mapper.select:
select s.id , s.host_id , s.title , s.description , s.address , s.price_per_hour , s.capacity , s.created_at , s.updated_at , s.is_deleted , si.id , si.space_id , si.image_url , si.is_main , si.created_at , si.updated_at , si.is_deleted from space s left join space_image si on s.id = si.id and si.is_main = 1 and si.is_deleted = 0 where s.is_deleted = 0
and (s.title like concat('%', #{keyword}, '%') or s.address like concat('%', #{keyword}, '%'))
order by s.id desc limit #{limit} offset #{offset}

mapper.update:
update space
set is_deleted = 1
where id = #{spaceId}
